import * as React from "react"
import type { HeadFC, PageProps } from "gatsby"

import Layout from "../components/Layout";
import SlideShow from "../components/Slideshow";
import { Container, Grid, Pagination } from "@mui/material";
import { CardStyled, PaginationContainer } from "../components/productsStyles";
import Product from "../components/Product";
import { navigate } from "gatsby"
import useProducts from "../storage/useProducts";

const IndexPage: React.FC<PageProps> = () => {
  const { products } = useProducts("");
  const goProductPage = (nameId: string) => {
    navigate(`/produtos/${nameId}`)
  }

  return (
    <Layout showHeaderCategories={true}>
      <SlideShow images={['/1.webp', '/2.webp']} />

      <Container>
        <Grid container spacing={2}>
          {products.map((product) => (
            <Grid key={product.id} item xs={12} sm={12} md={6} lg={4} xl={4} style={{ display: 'flex', justifyContent: 'center' }}>
              <Product product={product} onClick={() => goProductPage(product.nameId)} />
            </Grid>
          ))}
        </Grid>
      </Container>
    </Layout >
  )
}

export default IndexPage

export const Head: HeadFC = () => <title>Home Page</title>
